import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import authService from '../../services/authService';

const readCachedAccount = () => {
    try {
        const raw = localStorage.getItem('auth_user') || localStorage.getItem('user');
        if (!raw) {
            return null;
        }

        const parsed = JSON.parse(raw);
        return parsed && typeof parsed === 'object' ? parsed : null;
    } catch {
        return null;
    }
};

export default function AdminAccount() {
    const cachedAccount = readCachedAccount();

    const [user, setUser] = useState(cachedAccount);
    const [formData, setFormData] = useState({
        name: cachedAccount?.name || '',
        email: cachedAccount?.email || '',
        phone: cachedAccount?.phone || '',
        address: cachedAccount?.address || '',
        city: cachedAccount?.city || '',
        postal_code: cachedAccount?.postal_code || '',
    });
    const [saving, setSaving] = useState(false);
    const [loading, setLoading] = useState(!cachedAccount);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    const quickLinks = [
        { to: '/admin/dashboard', label: 'Dashboard' },
        { to: '/admin/products', label: 'Inventory' },
        { to: '/admin/orders', label: 'Orders' },
        { to: '/admin/users', label: 'Users' },
        { to: '/admin/customer-service', label: 'Customer Service' },
        { to: '/admin/analytics', label: 'Analytics' },
    ];

    useEffect(() => {
        loadAccount();
    }, []);

    const hydrateFromProfile = (profile) => {
        if (!profile || typeof profile !== 'object') {
            return;
        }

        setUser(profile);
        setFormData({
            name: profile.name || '',
            email: profile.email || '',
            phone: profile.phone || '',
            address: profile.address || '',
            city: profile.city || '',
            postal_code: profile.postal_code || '',
        });
    };

    const loadAccount = async () => {
        setLoading(true);
        setError('');

        try {
            const res = await authService.getProfile({ timeout: 20000 });
            const profile = res.data.user;
            hydrateFromProfile(profile);
        } catch (err) {
            const cachedRaw = localStorage.getItem('auth_user') || localStorage.getItem('user');
            if (cachedRaw) {
                try {
                    const cachedUser = JSON.parse(cachedRaw);
                    hydrateFromProfile(cachedUser);
                    // Keep the screen usable with cached data and avoid noisy errors.
                    setError('');
                } catch {
                    setError('Failed to load admin account');
                }
            } else {
                setError('Failed to load admin account');
            }
        } finally {
            setLoading(false);
        }
    };

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
        setSuccess('');
        setError('');
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setSaving(true);
        setError('');
        setSuccess('');

        try {
            let res;
            try {
                res = await authService.updateProfile(formData, { timeout: 30000 });
            } catch (firstErr) {
                const isTransient = !firstErr?.response || firstErr?.code === 'ECONNABORTED';
                if (!isTransient) {
                    throw firstErr;
                }

                // Retry once for transient timeout/network issues.
                res = await authService.updateProfile(formData, { timeout: 30000 });
            }

            hydrateFromProfile(res.data.user || user);
            setSuccess('Account updated successfully');
        } catch (err) {
            try {
                // If save request timed out but backend completed, this confirms and avoids false failure.
                const verifyRes = await authService.getProfile({ timeout: 15000 });
                const verifiedProfile = verifyRes?.data?.user;

                if (verifiedProfile && typeof verifiedProfile === 'object') {
                    hydrateFromProfile(verifiedProfile);
                    setSuccess('Account updated successfully');
                    setError('');
                    return;
                }
            } catch {
                // Keep original error handling below.
            }

            setError(err.response?.data?.message || 'Failed to update account');
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="admin-page-content admin-account page-shell">
            <div className="account-hero">
                <div>
                    <h1>Admin Account</h1>
                    <p>Profile settings, contact details, and quick navigation for the admin panel.</p>
                </div>
                <button type="button" className="btn btn-outline btn-sm" onClick={loadAccount}>
                    Refresh Account
                </button>
            </div>

            {error && <div className="alert alert-danger">{error}</div>}
            {success && <div className="alert alert-success">{success}</div>}

            <div className="admin-account-grid">
                <section className="account-card">
                    <h2>Profile Details</h2>
                    <div className="account-meta">
                        <div><span>Role</span><strong>{user?.role || 'admin'}</strong></div>
                        <div><span>Status</span><strong>{user?.is_active ? 'Active' : 'Inactive'}</strong></div>
                        <div><span>Member Since</span><strong>{user?.created_at ? new Date(user.created_at).toLocaleDateString() : '-'}</strong></div>
                        <div><span>Email</span><strong>{user?.email || '-'}</strong></div>
                    </div>

                    <div className="account-shortcuts">
                        <h3>Quick Links</h3>
                        <div className="account-shortcuts-grid">
                            {quickLinks.map((link) => (
                                <Link key={link.to} to={link.to} className="account-shortcut-link">
                                    {link.label}
                                </Link>
                            ))}
                        </div>
                    </div>
                </section>

                <section className="account-card">
                    <h2>Edit Account</h2>
                    <form onSubmit={handleSubmit} className="account-form">
                        <label>
                            Name
                            <input type="text" name="name" value={formData.name} onChange={handleChange} />
                        </label>
                        <label>
                            Email
                            <input type="email" name="email" value={formData.email} onChange={handleChange} disabled />
                        </label>
                        <label>
                            Phone
                            <input type="text" name="phone" value={formData.phone} onChange={handleChange} />
                        </label>
                        <label>
                            Address
                            <input type="text" name="address" value={formData.address} onChange={handleChange} />
                        </label>
                        <div className="account-form-row">
                            <label>
                                City
                                <input type="text" name="city" value={formData.city} onChange={handleChange} />
                            </label>
                            <label>
                                Postal Code
                                <input type="text" name="postal_code" value={formData.postal_code} onChange={handleChange} />
                            </label>
                        </div>
                        <button type="submit" className="btn btn-primary" disabled={saving}>
                            {saving ? 'Saving...' : 'Save Changes'}
                        </button>
                    </form>
                </section>
            </div>
        </div>
    );
}